// ── Parse Twilio WhatsApp payload ──────────────────────────────────────
// Twilio sends application/x-www-form-urlencoded; n8n decodes it for us.
const body = $input.first().json.body || $input.first().json;

const from     = body.From  || body.from  || '';   // e.g. whatsapp:+919876543210
const to       = body.To    || body.to    || '';   // Twilio number
const msgBody  = body.Body  || body.body  || '';   // User's message text
const msgSid   = body.MessageSid || '';

// Strip the 'whatsapp:' prefix to get a plain phone number
const phone = from.replace('whatsapp:', '').trim();

return [{ json: { from, to, phone, message: msgBody, messageSid: msgSid } }];

// ── Parse AI response and detect ACTION blocks ───────────────────────
const aiText = $input.first().json.choices?.[0]?.message?.content ||
               $input.first().json.text || '';

const phone   = $('Parse WhatsApp Message').first().json.phone;
const from    = $('Parse WhatsApp Message').first().json.from;

// Extract ACTION JSON if present
const actionMatch = aiText.match(/ACTION:(\{.*\})/s);
let action = null;
let replyText = aiText;

if (actionMatch) {
  try {
    action = JSON.parse(actionMatch[1]);
    // Remove the ACTION line from the user-facing reply
    replyText = aiText.replace(/ACTION:\{.*\}/s, '').trim();
  } catch (e) {
    // Malformed JSON – treat as plain text
    action = null;
  }
}

return [{ json: { aiResponse: aiText, replyText, action, phone, from } }];

// ── Build property listing URL ────────────────────────────────────────
const action   = $json.action;
const base     = $env.PROPERTY_WEBSITE_BASE_URL || 'https://www.yourrealestate.com/properties';

// Build query string from action parameters
const params = new URLSearchParams();
if (action.location)      params.set('location',      action.location);
if (action.property_type) params.set('type',          action.property_type);
if (action.budget)        params.set('max_price',     action.budget);

const listingUrl = `${base}?${params.toString()}`;

// Append the link to the AI's conversational reply
const fullReply = `${$json.replyText}\n\n🏘️ Browse matching properties here:\n${listingUrl}`;

return [{ json: { ...$json, fullReply, listingUrl } }];

