// ── Compose final WhatsApp reply after booking ────────────────────────
const action    = $('Parse AI Response').first().json.action;
const replyText = $('Parse AI Response').first().json.replyText;

const dt = new Date(action.preferred_datetime);
const dateStr = dt.toLocaleString('en-IN', { dateStyle: 'medium', timeStyle: 'short' });

const fullReply =
  `${replyText}\n\n` +
  `*Appointment Confirmed!*\n` +
  `Date & Time: ${dateStr}\n` +
  `Property: ${action.property}\n` +
  `A confirmation email has been sent to ${action.lead_email}.\n\n` +
  `Our agent will be in touch soon. Thank you!`;

return [{ json: { ...$json, fullReply, phone: $('Parse AI Response').first().json.phone, from: $('Parse AI Response').first().json.from } }];

// ── Send WhatsApp message via Twilio REST API ─────────────────────────
const accountSid  = $env.TWILIO_ACCOUNT_SID;
const authToken   = $env.TWILIO_AUTH_TOKEN;
const fromNumber  = $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';

// Get the resolved reply and recipient from whichever branch ran
const item = $input.first().json;
const toNumber = item.from || `whatsapp:${item.phone}`;
const messageBody = item.fullReply || item.replyText || 'Thank you for contacting us!';

const url = `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`;

const formData = new URLSearchParams({
  From: fromNumber,
  To: toNumber,
  Body: messageBody
});

const response = await fetch(url, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Authorization': 'Basic ' + Buffer.from(`${accountSid}:${authToken}`).toString('base64')
  },
  body: formData.toString()
});

const result = await response.json();
return [{ json: { twilioSid: result.sid, status: result.status, to: toNumber, body: messageBody } }];
